namespace Glacier.Polaris.Tests.ParityTests;

/// <summary>
/// Comprehensive parity tests comparing C# Glacier.Polaris output against
/// golden files generated by Python Polars (tests/parity/generate_parity_data.py).
/// Each test loads the golden JSON and verifies the C# engine produces identical results.
/// </summary>
public class ParityTests
{
    private readonly ITestOutputHelper _output;

    public ParityTests(ITestOutputHelper output)
    {
        _output = output;
    }

    #region Helpers

    private static string GoldenDir => Path.Combine(
        AppContext.BaseDirectory, @"..\..\..\..\parity\golden");

    private static object? ParseJsonElement(JsonElement el) => el.ValueKind switch
    {
        JsonValueKind.Null => null,
        JsonValueKind.Number when el.TryGetInt64(out var l) => (object)l,
        JsonValueKind.Number when el.TryGetDouble(out var d) => (object)d,
        JsonValueKind.String => el.GetString(),
        JsonValueKind.True => true,
        JsonValueKind.False => false,
        JsonValueKind.Array => ParseJsonArray(el),
        _ => el.GetRawText()
    };

    private static List<object?> ParseJsonArray(JsonElement el)
    {
        var list = new List<object?>();
        foreach (var child in el.EnumerateArray())
            list.Add(ParseJsonElement(child));
        return list;
    }

    /// <summary>Load expected values from a golden JSON file.</summary>
    private static Dictionary<string, List<object?>> LoadGolden(string name)
    {
        var path = Path.Combine(GoldenDir, $"{name}.json");
        var json = File.ReadAllText(path);
        var doc = JsonDocument.Parse(json);
        var result = new Dictionary<string, List<object?>>();
        foreach (var prop in doc.RootElement.EnumerateObject())
        {
            result[prop.Name] = ParseJsonArray(prop.Value);
        }
        return result;
    }

    /// <summary>Compare a C# DataFrame column with golden expected values.</summary>
    private static void AssertColumn(string colName, ISeries actual, List<object?> expected)
    {
        Assert.Equal(expected.Count, actual.Length);
        for (int i = 0; i < actual.Length; i++)
        {
            var exp = expected[i];
            if (exp is null)
            {
                Assert.True(actual.ValidityMask.IsNull(i),
                    $"Row {i} of '{colName}': expected null, got value");
            }
            else if (exp is long l)
            {
                var actualVal = actual.Get(i);
                if (actualVal is null) Assert.Fail($"Row {i} of '{colName}': expected {l}, got null");
                Assert.Equal(l, Convert.ToInt64(actualVal));
            }
            else if (exp is double d)
            {
                var actualVal = actual.Get(i);
                if (actualVal is null) Assert.Fail($"Row {i} of '{colName}': expected {d}, got null");
                Assert.Equal(d, Convert.ToDouble(actualVal), 6);
            }
            else if (exp is string s)
            {
                var actualVal = actual.Get(i)?.ToString();
                Assert.Equal(s, actualVal);
            }
            else if (exp is bool b)
            {
                var actualVal = actual.Get(i);
                if (actualVal is null) Assert.Fail($"Row {i} of '{colName}': expected {b}, got null");
                Assert.Equal(b, (bool)actualVal);
            }
            else if (exp is List<object?> expectedList)
            {
                // Nested array (e.g., ListSeries.Unique returns object[])
                var actualVal = actual.Get(i);
                if (actualVal is object[] arr)
                {
                    Assert.Equal(expectedList.Count, arr.Length);
                    for (int j = 0; j < arr.Length; j++)
                    {
                        var ae = arr[j];
                        var ee = expectedList[j];
                        if (ee is null)
                            Assert.Null(ae);
                        else if (ee is long le)
                            Assert.Equal(le, Convert.ToInt64(ae));
                        else if (ee is double de)
                            Assert.Equal(de, Convert.ToDouble(ae), 6);
                        else if (ee is string se)
                            Assert.Equal(se, ae?.ToString());
                        else if (ee is bool be)
                            Assert.Equal(be, (bool)ae!);
                    }
                }
                else
                {
                    Assert.Fail($"Row {i} of '{colName}': expected list, got {actualVal?.GetType().Name ?? "null"}");
                }
            }
        }
    }

    /// <summary>Verify a DataFrame matches the golden file.</summary>
    private static void AssertGolden(string name, DataFrame actual)
    {
        var golden = LoadGolden(name);
        foreach (var (colName, expected) in golden)
        {
            var actualCol = actual.GetColumn(colName);
            AssertColumn(colName, actualCol, expected);
        }
    }

    /// <summary>Shorthand to get a series from a DataFrame.</summary>
    private static Int32Series I32(DataFrame df, string name) =>
        (Int32Series)df.GetColumn(name);

    private static Float64Series F64(DataFrame df, string name) =>
        (Float64Series)df.GetColumn(name);

    private static Utf8StringSeries Str(DataFrame df, string name) =>
        (Utf8StringSeries)df.GetColumn(name);

    private static BooleanSeries Bool(DataFrame df, string name) =>
        (BooleanSeries)df.GetColumn(name);

