    // Extended types - Int8, Int16, Int64, UInt*, Float32

    [Fact]
    public void Tier1_Int8()
    {
        var series = new Int8Series("a", 3);
        series.Memory.Span[0] = 1; series.ValidityMask.SetValid(0);
        series.Memory.Span[1] = 2; series.ValidityMask.SetValid(1);
        series.Memory.Span[2] = 3; series.ValidityMask.SetValid(2);
        var df = new DataFrame(new ISeries[] { series });
        var result = df.Select((Expr.Col("a") + 10).Alias("plus"));
        var actual = (Int32Series)result.GetColumn("plus");
        var golden = LoadGolden("tier1_int8");
        Assert.Equal(3, actual.Length);
        for (int i = 0; i < 3; i++)
            Assert.Equal(golden["plus"][i], (long)actual.Memory.Span[i]);
    }

