    [Fact]
    public void Tier8_DateExtract()
    {
        var epoch = new DateTime(1970, 1, 1, 0, 0, 0, DateTimeKind.Utc);
        var dates = new[]
        {
            epoch.AddDays((int)(new DateTime(2026, 5, 2) - epoch).TotalDays),
            epoch.AddDays((int)(new DateTime(2025, 12, 25) - epoch).TotalDays),
            epoch.AddDays((int)(new DateTime(2024, 3, 15) - epoch).TotalDays),
        };
        var dateSeries = new DateSeries("date", dates);
        var df = new DataFrame(new ISeries[] { dateSeries });
        var result = df.Select(
            Expr.Col("date").Dt().Year().Alias("year"),
