            Expr.Col("date").Dt().Day().Alias("day")
        );
        AssertGolden("tier8_date_extract", result);
    }

    [Fact]
    public void Tier8_DatetimeExtract()
    {
        var dt1 = new DateTime(2026, 5, 2, 10, 30, 45, DateTimeKind.Utc)
            .AddTicks(123456);
        var dt2 = new DateTime(2025, 12, 25, 0, 0, 0, DateTimeKind.Utc);
        var epoch = new DateTime(1970, 1, 1, 0, 0, 0, DateTimeKind.Utc);
        var ticks1 = (dt1.ToUniversalTime().Ticks - epoch.Ticks) * 100;
        var ticks2 = (dt2.ToUniversalTime().Ticks - epoch.Ticks) * 100;

        var dtSeries = new DatetimeSeries("dt", 2);
        dtSeries.Memory.Span[0] = ticks1;
        dtSeries.ValidityMask.SetValid(0);
        dtSeries.Memory.Span[1] = ticks2;
        dtSeries.ValidityMask.SetValid(1);

        var df = new DataFrame(new ISeries[] { dtSeries });
        var result = df.Select(
            Expr.Col("dt").Dt().Year().Alias("year"),
            Expr.Col("dt").Dt().Month().Alias("month"),
            Expr.Col("dt").Dt().Day().Alias("day"),
            Expr.Col("dt").Dt().Hour().Alias("hour"),
            Expr.Col("dt").Dt().Minute().Alias("minute"),
            Expr.Col("dt").Dt().Second().Alias("second")
        );
        AssertGolden("tier8_datetime_extract", result);
    }

    [Fact]
    public void Tier8_TemporalDiff()
    {
        var epoch = new DateTime(1970, 1, 1, 0, 0, 0, DateTimeKind.Utc);
        var dt1 = new DateTime(2026, 5, 2, 10, 0, 0, DateTimeKind.Utc);
        var dt2 = new DateTime(2026, 5, 1, 10, 0, 0, DateTimeKind.Utc);
        var t1 = (dt1.Ticks - epoch.Ticks) * 100;
        var t2 = (dt2.Ticks - epoch.Ticks) * 100;

        var s1 = new DatetimeSeries("dt1", 1);
        s1.Memory.Span[0] = t1; s1.ValidityMask.SetValid(0);
        var s2 = new DatetimeSeries("dt2", 1);
        s2.Memory.Span[0] = t2; s2.ValidityMask.SetValid(0);

        var df = new DataFrame(new ISeries[] { s1, s2 });
        var result = df.Lazy()
            .Select((Expr.Col("dt1") - Expr.Col("dt2")).Alias("diff"))
            .WithColumns(
                Expr.Col("diff").TotalDays().Alias("days"),
                Expr.Col("diff").TotalHours().Alias("hours"),
                Expr.Col("diff").TotalSeconds().Alias("seconds")
            )
            .Collect().GetAwaiter().GetResult();

        var days = (Float64Series)result.GetColumn("days");
        Assert.Equal(1, (int)days.Memory.Span[0]);
        var hours = (Float64Series)result.GetColumn("hours");
        Assert.Equal(24, (int)hours.Memory.Span[0]);
        var seconds = (Float64Series)result.GetColumn("seconds");
        Assert.Equal(86400, (int)seconds.Memory.Span[0]);
    }

