    [Fact]
    public void Tier13_Implode()
    {
        var df = new DataFrame(new ISeries[]
        {
            Utf8StringSeries.FromStrings("g", ["x", "x", "y", "y", "y"]),
            Int32Series.FromValues("v", [1, 2, 3, 4, 5]),
        });
        var result = df.GroupBy("g").Agg(
            ("v", "implode")
        );

        var golden = LoadGolden("tier13_implode");
        var implodeCol = result.GetColumn("v_implode") as Glacier.Polaris.Data.ListSeries;
        Assert.NotNull(implodeCol);

        var gCol = result.GetColumn("g") as Glacier.Polaris.Data.Utf8StringSeries;
        Assert.NotNull(gCol);

        var goldenG = golden["g"];
        var goldenImploded = golden["imploded"];
        var expectedByGroup = new Dictionary<string, List<object?>>();
        for (int i = 0; i < goldenG.Count; i++)
        {
            var gVal = goldenG[i]?.ToString() ?? "";
            if (goldenImploded[i] is List<object?> subList)
                expectedByGroup[gVal] = subList;
        }

        for (int i = 0; i < implodeCol.Length; i++)
        {
            var g = gCol.GetString(i) ?? "";
            var grpVals = implodeCol.Get(i);
            Assert.True(expectedByGroup.ContainsKey(g), $"Group '{g}' not found in golden");

            var expectedVals = expectedByGroup[g];
            if (grpVals is object[] arr)
            {
                Assert.Equal(expectedVals.Count, arr.Length);
                for (int j = 0; j < arr.Length; j++)
                {
                    if (expectedVals[j] is long le)
                        Assert.Equal(le, Convert.ToInt64(arr[j]));
                    else if (expectedVals[j] is double de)
                        Assert.Equal(de, Convert.ToDouble(arr[j]), 6);
                }
            }
            else
            {
                Assert.Fail($"Expected array for group {g}, got {grpVals?.GetType().Name}");
            }
        }
    }

